86	  ): ResponseHandler<ReadableStream<ParseResult<T>>> =>
87	  async ({ response }: { response: Response }) => {
88	    const responseHeaders = extractResponseHeaders(response);
89	
90	    if (response.body == null) {
91	      throw new EmptyResponseBodyError({});
92	    }
93	
94	    return {
95	      responseHeaders,
96	      value: parseJsonEventStream({
97	        stream: response.body,
