17	interface TogetherAIImageModelConfig {
18	  provider: string;
19	  baseURL: string;
20	  headers: () => Record<string, string>;
21	  fetch?: FetchFunction;
22	  _internal?: {
23	    currentDate?: () => Date;
24	  };
25	}
