import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
  Resolvable,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixel-art-image-settings';
import { pixelArtImageModelOptionsSchema } from './pixel-art-image-options';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

// Response schema
const pixelArtImageResponseSchema = z.object({
  images: z.array(z.object({ b64_json: z.string() })),
});

// Error schema
const pixelArtErrorSchema = z.object({
  error: z.object({ message: z.string() }),
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0])
    : Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal, files, mask } = options;
    const warnings: Array<SharedV3Warning> = [];
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Warn on unsupported features
    if (aspectRatio != null) {
      warnings.push({ type: 'unsupported', feature: 'aspectRatio',
        details: 'PixelArt provider does not support aspectRatio. Use `size` instead.' });
    }
    if (files != null && files.length > 0) {
      warnings.push({ type: 'unsupported', feature: 'image input',
        details: 'PixelArt provider does not support image-to-image generation.' });
    }
    if (mask != null) {
      warnings.push({ type: 'unsupported', feature: 'mask',
        details: 'PixelArt provider does not support inpainting.' });
    }

    // Parse provider options (style, pixelDensity)
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Build size object
    let requestSize: { width: number; height: number } | undefined;
    if (size != null) {
      const [width, height] = size.split('x').map(Number);
      requestSize = { width, height };
    }

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        seed,
        ...(requestSize != null ? { size: requestSize } : {}),
        ...(pixelArtOptions?.style != null ? { style: pixelArtOptions.style } : {}),
        ...(pixelArtOptions?.pixelDensity != null ? { pixel_density: pixelArtOptions.pixelDensity } : {}),
      },
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: data => data.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(pixelArtImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(img => img.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}
```

### Step 10 — `src/pixel-art-provider.ts`

```ts
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import { FetchFunction, withoutTrailingSlash, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { loadApiKey } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixel-art-image-model';
import { PixelArtImageModelId } from './pixel-art-image-settings';
import { VERSION } from './version';

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

export interface PixelArtProviderSettings {
  /** PixelArt API key. Defaults to PIXELART_API_KEY env var. */
  apiKey?: string;
  /** Override base URL. Defaults to https://api.pixelart.ai/v1. */
  baseURL?: string;
  /** Additional headers to include in every request. */
  headers?: Record<string, string>;
  /** Custom fetch implementation. */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  /** Creates an image generation model. */
  image(modelId: PixelArtImageModelId): ImageModelV3;
  /** Creates an image generation model (alias). */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? DEFAULT_BASE_URL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixel-art/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3',
    imageModel: createImageModel,
    image: createImageModel,
    languageModel(modelId: string) {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel(modelId: string) {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

/** Default PixelArt provider instance. */
export const pixelArt = createPixelArt();
```

