### Step 12 — `src/pixel-art-image-model.test.ts`

Use `@ai-sdk/test-server/with-vitest` to mock the API, matching the pattern in `fal-image-model.test.ts`:

```ts
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixel-art-image-model';

const TEST_URL = 'https://api.pixelart.ai/v1';
const GENERATE_URL = `${TEST_URL}/images/generate`;

function createModel(overrides = {}) {
  return new PixelArtImageModel('pixelart/standard', {
    provider: 'pixelart.image',
    baseURL: TEST_URL,
    headers: { Authorization: 'Bearer test-key' },
    ...overrides,
  });
}

const BASE_OPTIONS = {
  prompt: 'A pixel art forest',
  n: 1, size: undefined, aspectRatio: undefined,
  seed: undefined, providerOptions: {}, files: undefined, mask: undefined,
};

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [GENERATE_URL]: {
      response: {
        type: 'json-value',
        body: { images: [{ b64_json: 'base64encodedimage==' }] },
      },
    },
  });

  it('sends correct request body', async () => {
    await createModel().doGenerate({ ...BASE_OPTIONS, prompt: 'A pixel art castle', n: 2, size: '512x512' });
    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      model: 'pixelart/standard',
      prompt: 'A pixel art castle',
      n: 2,
      size: { width: 512, height: 512 },
    });
  });

  it('returns base64 images', async () => {
    const result = await createModel().doGenerate(BASE_OPTIONS);
    expect(result.images).toStrictEqual(['base64encodedimage==']);
  });

  it('passes style and pixelDensity provider options', async () => {
    await createModel().doGenerate({
      ...BASE_OPTIONS,
      providerOptions: { pixelart: { style: '8bit', pixelDensity: 50 } },
    });
    const body = await server.calls[0].requestBodyJson;
    expect(body).toMatchObject({ style: '8bit', pixel_density: 50 });
  });

  it('warns on unsupported aspectRatio', async () => {
    const result = await createModel().doGenerate({ ...BASE_OPTIONS, aspectRatio: '16:9' });
    expect(result.warnings).toContainEqual(
      expect.objectContaining({ type: 'unsupported', feature: 'aspectRatio' }),
    );
  });

  it('warns on unsupported image files input', async () => {
    const result = await createModel().doGenerate({
      ...BASE_OPTIONS,
      files: [{ type: 'url', url: 'https://example.com/img.png' }],
    });
    expect(result.warnings).toContainEqual(
      expect.objectContaining({ type: 'unsupported', feature: 'image input' }),
    );
  });
});
```

