      it('should warn when aspectRatio is provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: '16:9',
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        });

        expect(result.warnings).toMatchInlineSnapshot(`
          [
            {
              "details": "PixelArt does not support the \`aspectRatio\` option. Use \`size\` instead.",
              "feature": "aspectRatio",
              "type": "unsupported",
            },
          ]
        `);
      });

      it('should warn when files are provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
