          [
            {
              "details": "PixelArt does not support input image files.",
              "feature": "input files",
              "type": "unsupported",
            },
          ]
        `);
      });

      it('should warn when mask is provided', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: { type: 'url', url: 'https://example.com/mask.png' },
        });

        expect(result.warnings).toMatchInlineSnapshot(`
          [
            {
              "details": "PixelArt does not support mask-based image editing.",
              "feature": "mask",
              "type": "unsupported",
            },
          ]
        `);
      });
    });

    describe('response metadata', () => {
      it('should include timestamp, headers and modelId in response', async () => {
        const testDate = new Date('2024-01-01T00:00:00Z');
        const model = createBasicModel({
          currentDate: () => testDate,
        });

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        });

        expect(result.response).toStrictEqual({
          timestamp: testDate,
          modelId: 'pixelart/standard',
          headers: expect.any(Object),
        });
      });

      it('should include response headers from API call', async () => {
        server.urls['https://api.example.com/images/generate'].response = {
          type: 'json-value',
          body: {
            data: [{ b64_json: 'test-base64-content' }],
          },
          headers: {
            'x-request-id': 'test-request-id',
            'content-length': '64',
          },
        };

        const model = createBasicModel();
        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        });

        expect(result.response.headers).toStrictEqual({
          'x-request-id': 'test-request-id',
          'content-type': 'application/json',
          'content-length': '64',
        });
      });
    });
  });
});

