import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixel-art-image-settings';
import { pixelArtImageModelOptionsSchema } from './pixel-art-image-options';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'input files',
        details: 'PixelArt does not support input image files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support mask-based image editing.',
      });
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Parse size into width/height components
    let width: number | undefined;
    let height: number | undefined;
    if (size != null) {
      const [w, h] = size.split('x').map(Number);
      width = w;
      height = h;
    }

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        seed,
        ...(width != null && height != null ? { width, height } : {}),
        ...(pixelArtOptions?.style != null
          ? { style: pixelArtOptions.style }
          : {}),
        ...(pixelArtOptions?.pixelDensity != null
          ? { pixel_density: pixelArtOptions.pixelDensity }
          : {}),
        response_format: 'base64',
      },
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: data => data.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

// Response schema — focused on what is needed for the implementation
const pixelArtImageResponseSchema = z.object({
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

// Error schema
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
  }),
});

